const input = $input.first().json;

// Read Responder LLM output (orchestrator/responder split)
let responseText = '';
try { responseText = $('Responder LLM').first().json.text || ''; } catch(e) {}
if (!responseText) {
  try { responseText = $('Responder LLM').first().json.output || ''; } catch(e) {}
}
if (!responseText) responseText = input.text || input.output || input.response || '';
if (!responseText && input.message) responseText = input.message;

const agentName = (() => { try { return $('Assemble System Prompt').first().json.agentName || 'Luke'; } catch(e) { return input.agentName || 'Luke'; } })();
const contactId = (() => { try { return $('Assemble System Prompt').first().json.contactId || ''; } catch(e) { return input.contactId || input.contact_id || ''; } })();
const channelType = (() => { try { return $('Assemble System Prompt').first().json.channelType || ''; } catch(e) { return input.channelType || input.channel || ''; } })();

const nameParts = agentName.split(' ');
const firstName = nameParts[0] || 'Agent';
const fnLower = firstName.toLowerCase();

// Escalation: orchestrator emits should_escalate in its packet.
// Validate Orchestrator Packet surfaces it as a top-level field.
let shouldEscalate = false;
let escalationReason = null;
try { shouldEscalate = !!$('Validate Orchestrator Packet').first().json.should_escalate; } catch(e) {}
try { escalationReason = $('Validate Orchestrator Packet').first().json.escalation_reason || null; } catch(e) {}
const action = shouldEscalate ? 'escalate' : 'send';

return [{
  json: {
    output: responseText,
    action,
    shouldEscalate,
    escalationReason,
    responseText,
    agentName,
    contactId,
    channelType
  }
}];

// Prepare tier-specific response instructions for the AI Agent
// Pull tier/sentiment/sms_action from Parse Sentiment directly — input $json may be from Apply L1: Mark Lead (no tier)
const agentName = (() => {
  try { return $('Get Agent Config').first().json.agent_name; } catch(e) {}
  try { return $('Get Outbound Agent Config').first().json.agent_name; } catch(e) {}
  return 'the agent';
})();
const ps = (() => { try { return $('Parse Sentiment').first().json; } catch(e) { return {}; } })();
const tier = ps.tier || $json.tier || 'normal';
const sentiment = ps.sentiment || $json.sentiment || 'neutral';
const smsAction = ps.sms_action || $json.sms_action || 'none';

const tierInstructions = {
  tier_1_confused: {
    instruction: `TIER 1 RESPONSE - CONFUSED/ANNOYED\nThe lead is confused or annoyed but has NOT opted out.\n\nYour response MUST:\n- De-escalate the situation\n- Clarify who you are: "I'm part of ${agentName}'s team and sent an email earlier this week introducing myself."\n- Clarify your role: "My role is to help coordinate communication so everyone we work with gets the attention they deserve."\n- STOP after clarifying - no question, no business ask\n\nExample: "Totally fair... I should clarify. I'm part of ${agentName}'s team and sent an email earlier this week introducing myself. My role is to help coordinate communication so everyone we work with gets the attention they deserve."\n\nDO NOT: Ask questions, make business asks, apologize excessively, push appointments`,
    suppressSMS: false,
    pauseDays: 0
  },
  tier_2_hostile: {
    instruction: `TIER 2 RESPONSE - HOSTILE (NO EXPLICIT STOP)\nThe lead is hostile but has NOT explicitly opted out.\n\nYour response MUST be brief and respectful. Example: "Understood, no worries at all." or "Got it, I'll stop reaching out for now."\n\nDO NOT: Apologize, explain, offer removal, ask questions, defend the company, pivot to newsletter.`,
    suppressSMS: false,
    pauseDays: 30
  },
  tier_3_optout: {
    instruction: `TIER 3 RESPONSE - EXPLICIT OPT-OUT\nThe lead has explicitly requested to stop contact.\n\nYour response MUST be a brief respectful farewell. Example: "Got it, I'll stop reaching out. Wishing you the best." or "Understood. Take care."\n\nDO NOT: Persuade, defend, offer alternatives, reopen conversation, ask if they want anything else, apologize, mention the newsletter.`,
    suppressSMS: true,
    pauseDays: -1
  },
  emotional: {
    instruction: `EMOTIONAL RESPONSE - SENSITIVE SITUATION\nThe lead has shared something emotionally difficult.\n\nExample: "I'm really sorry to hear that... that's incredibly difficult. Is there anything we can do to support you right now?"\n\nDO NOT: Push appointments, explain processes, mention automation, be transactional\n\nNOTE: Human agent will be notified.`,
    suppressSMS: false,
    pauseDays: 0,
    escalateHuman: true
  },
  turnaround: {
    instruction: `TURNAROUND RESPONSE\nThe lead previously opted out and has now re-engaged warmly.\n\nYour response MUST:\n- Skip the big greeting. They didn't just walk in fresh.\n- Brief natural acknowledgment in your own words ("no worries", "good to hear", "all good" — pick what fits)\n- Then address what they actually said\n- Keep it warm but low-key\n\nDO NOT: Mention the prior opt-out, apologize, reference the silence, use a canned phrase.`,
    suppressSMS: false,
    pauseDays: 0
  },
  declined_meeting: {
    instruction: '',
    suppressSMS: false,
    pauseDays: 0
  },
  booking: {
    instruction: '',
    suppressSMS: false,
    pauseDays: 0
  },
  normal: {
    instruction: '',
    suppressSMS: false,
    pauseDays: 0
  }
};

const config = tierInstructions[tier] || tierInstructions.normal;

return {
  json: {
    ...$json,
    tier: tier,
    sentiment: sentiment,
    sms_action: smsAction,
    tierInstruction: config.instruction,
    shouldSuppressSMS: config.suppressSMS || smsAction === 'permanent_suppress',
    smsPauseDays: smsAction === 'pause_30_days' ? 30 : config.pauseDays,
    shouldEscalateHuman: config.escalateHuman || false,
    isTieredResponse: tier !== 'normal'
  }
};

const input = $input.first().json;
const currentMessage = (input.message || input.message_body || '').toLowerCase();

const keywordPatterns = {
  pricing: /\b(price|pricing|cost|fee|rate|charge|dollar|\$|expensive|cheap|afford)\b/i,
  property: /\b(house|home|property|apartment|condo|bedroom|bath|sqft|square|lot)\b/i,
  location: /\b(address|where|location|area|neighborhood|city|street|zip)\b/i,
  availability: /\b(available|availability|vacancy|vacant|ready|move.?in|when|schedule|showing)\b/i,
  application: /\b(apply|application|approve|qualify|credit|income|lease|rent)\b/i,
  maintenance: /\b(repair|fix|broken|leak|maintenance|issue|problem|work.?order)\b/i
};

const foundKeywords = [];
for (const [category, pattern] of Object.entries(keywordPatterns)) {
  if (pattern.test(currentMessage)) {
    foundKeywords.push(category);
  }
}

return [{
  json: {
    ...input,
    keywords: foundKeywords,
    has_keywords: foundKeywords.length > 0,
    keyword_count: foundKeywords.length
  }
}];

// Merge recent messages + keyword-matched messages, deduplicate by id
const allMessages = $input.all().map(item => item.json);

// Deduplicate by id (not message_id)
const seen = new Set();
const uniqueMessages = [];

for (const msg of allMessages) {
  const msgId = msg.id || msg.message_id; // Support both field names
  if (!seen.has(msgId)) {
    seen.add(msgId);
    uniqueMessages.push(msg);
  }
}

// Sort by timestamp (newest first)
uniqueMessages.sort((a, b) => {
  const timeA = new Date(a.timestamp).getTime();
  const timeB = new Date(b.timestamp).getTime();
  return timeB - timeA;
});

// Return as array of items (n8n format)
return uniqueMessages.map(msg => ({ json: msg }));

