  if (!AI_COLLECTABLE.has(name)) {
    validationLog.push({ name, value: String(value), skipped: 'not_in_ai_collectable_whitelist' });
    continue;
  }
  const fieldDef = ghlByName[name];
  if (!fieldDef || !fieldDef.id) {
    validationLog.push({ name, value: String(value), skipped: 'no_match_in_ghl_location' });
    continue;
  }
  // Validate against GHL's live picklistOptions (no stale config)
  const opts = fieldDef.picklistOptions;
