const input = $json;

let parsed;
try {
  let text = '';
  if (input.content && Array.isArray(input.content)) {
    text = input.content.map(c => c.text || '').join('');
  } else if (input.message && input.message.content) {
    text = input.message.content;
  } else if (input.text) {
    text = input.text;
  } else if (typeof input === 'string') {
    text = input;
  } else {
    text = JSON.stringify(input);
  }

  const fenceMatch = text.match(/\`\`\`(?:json)?\n?([\s\S]*?)\`\`\`/);
  if (fenceMatch) {
    text = fenceMatch[1].trim();
  }

  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (e) {
  parsed = {
    sentiment: 'neutral',
    tier: 'normal',
    signal_type: 'none',
    confidence: 'low',
    action: 'continue',
    sms_action: 'none',
    pipeline_update: 'no_change',
    message_intent: 'Parse error: ' + e.message,
    reason: 'Failed to parse AI response - defaulting to normal tier',
    should_suppress: false,
    suppress_reason: 'none',
    block_level: null
  };
}

let tier = parsed.tier || 'normal';
if (!parsed.tier && parsed.action) {
  if (parsed.action === 'opt_out_immediately') tier = 'tier_3_optout';
  else if (parsed.action === 'flag_review') tier = 'tier_2_hostile';
  else if (parsed.action === 'human_escalation') tier = 'emotional';
  else if (parsed.action === 'ignore') tier = 'normal';
  else if (parsed.action === 'booking') tier = 'booking';
}

const validActions = ['opt_out', 'flag_review', 'ignore', 'human_escalation', 'continue', 'booking'];

// PRIORITY 1: trust AI's action if it's one of the 6 valid values
let action = validActions.includes(parsed.action) ? parsed.action : null;

// PRIORITY 2: fallback — derive from tier when AI did not provide a valid action
if (!action) {
  if (tier === 'tier_3_optout') action = 'opt_out';
  else if (tier === 'tier_2_hostile') action = 'flag_review';
  else if (tier === 'spam') action = 'ignore';
  else if (tier === 'emotional') action = 'human_escalation';
  else if (tier === 'booking') action = 'booking';
  else action = 'continue'; // normal, tier_1_confused, declined_meeting, turnaround
}

// SAFETY: final guardrail — only the 6 valid values pass
if (!validActions.includes(action)) {
  action = 'continue';
}

// BLOCK LEVEL: trust classifier's block_level. Only default to L1 when classifier didn't specify.
let blockLevel = (parsed.block_level === 1 || parsed.block_level === 2) ? parsed.block_level : null;
if (action === 'opt_out' && blockLevel === null) blockLevel = 1; // default L1 only when classifier did not specify
if (action !== 'opt_out' && action !== 'ignore') blockLevel = null; // other actions do not need block level

return {
  json: {
    sentiment: parsed.sentiment || 'neutral',
    tier: tier,
    signal_type: parsed.signal_type || 'none',
    confidence: parsed.confidence || 'low',
    action: action,
    sms_action: parsed.sms_action || 'none',
    pipeline_update: parsed.pipeline_update || 'no_change',
    message_intent: parsed.message_intent || parsed.reasoning || '',
    reason: parsed.reason || parsed.reasoning || '',
    should_suppress: parsed.should_suppress === true,
    suppress_reason: parsed.suppress_reason || 'none',
    block_level: blockLevel
  }
};

const d = $input.first().json;

return [{
  json: {
    ...d,
    currentMessage: d.currentMessage || '',
    historyText: d.messageHistory || 'No previous messages',
    conversationSummary: d.conversationSummary || 'No summary',
    lastIntent: 'none',
    agentName: d.agentName || 'Luke Gilbert',
    contactId: d.contactId || '',
    locationId: d.locationId || '',
    firstName: d.firstName || 'Contact',
    pipelineStage: d.pipelineStage || 'MONTHLY',
    pipelineState: d.pipelineState || 'warm'
  }
}];

