  s = s.replace(/\.\s*,/g, '.');
  s = s.replace(/  +/g, ' ');
  s = s.replace(/,(\S)/g, ', $1');
  s = s.replace(/\.([A-Z])/g, '. $1');
  s = s.replace(/,\s*$/g, '.');
  return s.trim();
}

const rawResponseText = (input.responseText || input.output || '').toString().trim();
const normalized = normalizeStyle(rawResponseText);

return [{ json: Object.assign({}, input, {
  responseText: normalized,
  output: normalized
}) }];

// Validates orchestrator JSON packet, builds degraded fallback if invalid.
// Robust to: ```json fences, trailing prose, partial truncation.
const input = $input.first().json;
let packet = null;
let packet_valid = false;
const packet_errors = [];
const raw = input.output;

function extractFirstJsonObject(s) {
  // Find the first '{' in the string
  const start = s.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  let inString = false;
  let escape = false;
  for (let i = start; i < s.length; i++) {
    const c = s[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (c === '{') depth++;
    else if (c === '}') {
      depth--;
      if (depth === 0) return s.slice(start, i + 1);
    }
  }
  return null; // unbalanced
}

if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
  packet = raw;
  const required = ['response_goal', 'tone'];
  for (const k of required) { if (!(k in packet)) packet_errors.push('missing:' + k); }
  if (packet_errors.length === 0) packet_valid = true;
} else if (typeof raw === 'string') {
  let cleaned = raw.trim();
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').trim();
  // Try direct parse first
  let parseTarget = cleaned;
  // If there's a closing fence, take only what's before it
  const fenceClose = parseTarget.indexOf('```');
  if (fenceClose >= 0) parseTarget = parseTarget.slice(0, fenceClose).trim();
  // Extract first balanced JSON object
  const extracted = extractFirstJsonObject(parseTarget);
  if (!extracted) {
    packet_errors.push('no_balanced_json_object_found');
  } else {
    try {
      packet = JSON.parse(extracted);
      if (!packet || typeof packet !== 'object' || Array.isArray(packet)) {
        packet_errors.push('not_object_after_parse');
      } else {
        const required = ['response_goal', 'tone'];
        for (const k of required) { if (!(k in packet)) packet_errors.push('missing:' + k); }
        if (packet_errors.length === 0) packet_valid = true;
      }
    } catch (e) {
      packet_errors.push('json_parse_failed:' + (e && e.message ? e.message.slice(0, 200) : 'unknown'));
    }
  }
} else {
  packet_errors.push('output_missing_or_wrong_type:' + (typeof raw));
}

if (!packet_valid) {
  const channel = (() => { try { return $('Assemble System Prompt').first().json.channelType || 'sms'; } catch(e) { return 'sms'; } })();
  const firstName = (() => { try { return $('Assemble System Prompt').first().json.firstName || 'there'; } catch(e) { return 'there'; } })();
  packet = { schema_version: 'orchestrator_packet.v1', should_send: true, response_goal: 'Respond briefly and naturally to the lead. Acknowledge them in one short sentence and ask one clarifying question. Do not invent facts, appointment times, prices, or commitments.', tone: 'warm', verified_facts: { lead_first_name: firstName, today: new Date().toISOString().slice(0, 10), channel: channel, appointment_status: 'none', available_slots: [], newsletter_status: 'not_offered' }, must_not_say: ['I am SMRT', 'I am AI'], agent_voice_prompt: 'Calm, brief, warm. One idea per message. No filler acknowledgements.', recent_turns: [], degraded: true };
}

// Surface escalation flag (default false if not present)
const should_escalate = !!(packet && packet.should_escalate);
const escalation_reason = (packet && packet.escalation_reason) || null;
return [{ json: { ...input, orchestrator_packet: packet, packet_valid, packet_errors, should_escalate, escalation_reason, responseText: null } }];

