parameters.jsCode:
const apiKey = $('Get Agent Config').first().json.ghl_api_key || '';
const pipelineConfig = $('Get Agent Config').first().json.pipeline_config || {};
const contactId = $('LeadDetails').first().json.contact_id || '';
const locationId = $('LeadDetails').first().json.location_id || '';

const incubator = pipelineConfig.incubator || {};
const pipelineId = incubator.id;
const stageId = (incubator.stages || {}).DNC;

if (!apiKey || !contactId || !pipelineId || !stageId) {
  return [{ json: { action: 'skipped', reason: 'missing_config', contactId, hasKey: !!apiKey, hasPipeline: !!pipelineId, hasDncStage: !!stageId } }];
}

const headers = {
  'Authorization': 'Bearer ' + apiKey,
  'Version': '2021-07-28',
  'Content-Type': 'application/json'
};

let opportunityId = null;
try {
  const searchResp = await fetch('https://services.leadconnectorhq.com/opportunities/search?location_id=' + locationId + '&contact_id=' + contactId, {
    method: 'GET', headers
  });
  const searchData = await searchResp.json();
  if (searchData.opportunities && searchData.opportunities.length > 0) {
    opportunityId = searchData.opportunities[0].id;
  }
} catch(e) {}

let result = {};

if (opportunityId) {
  try {
    const resp = await fetch('https://services.leadconnectorhq.com/opportunities/' + opportunityId, {
      method: 'PUT', headers,
      body: JSON.stringify({ pipelineId, pipelineStageId: stageId })
    });
    if (!resp.ok) {
      const errText = await resp.text();
      result = { action: 'update_failed', opportunityId, error: 'HTTP ' + resp.status + ': ' + errText.slice(0,200), success: false };
    } else {
      result = { action: 'updated', opportunityId, pipelineId, stageId, targetStage: 'DNC', success: true };
    }
  } catch(e) {
    result = { action: 'update_failed', opportunityId, error: e.message, success: false };
  }
} else {
  result = { action: 'no_opp_found', success: true };
}

result.contactId = contactId;
return [{ json: result }];

